export const KatexJS = '';
export const KatexCSS = '';
export const KatexAutoRenderJS = '';
export const FontMainRegular = '';
export const FontMathItalic = '';
export const FontAMSRegular = '';
export const FontSize1Regular = '';
export const FontSize2Regular = '';
export function getKatexHtmlHead() { return ` <style> @font-face { font-family: 'KaTeX_Main'; src: url('data:font/ttf;base64,${FontMainRegular}') format('truetype'); font-weight: normal; font-style: normal; } @font-face { font-family: 'KaTeX_Math'; src: url('data:font/ttf;base64,${FontMathItalic}') format('truetype'); font-weight: normal; font-style: italic; } @font-face { font-family: 'KaTeX_AMS'; src: url('data:font/ttf;base64,${FontAMSRegular}') format('truetype'); font-weight: normal; font-style: normal; } @font-face { font-family: 'KaTeX_Size1'; src: url('data:font/ttf;base64,${FontSize1Regular}') format('truetype'); font-weight: normal; font-style: normal; } @font-face { font-family: 'KaTeX_Size2'; src: url('data:font/ttf;base64,${FontSize2Regular}') format('truetype'); font-weight: normal; font-style: normal; } </style> <script> (function() { var style = document.createElement('style'); style.innerHTML = atob('${KatexCSS}'); document.head.appendChild(style); var script = document.createElement('script'); script.innerHTML = atob('${KatexJS}'); document.head.appendChild(script); var autoRender = document.createElement('script'); autoRender.innerHTML = atob('${KatexAutoRenderJS}'); document.head.appendChild(autoRender); })(); </script> `; }
